{
  "shots": [
    {
      "shot_id": "SH02",
      "priority": "P0",
      "intent": "把石川从清晨离站后的外部行动转入警视厅办公室的最终判断线，首次呈现案件卷宗并让他克制地打开。",
      "duration_sec": 4,
      "shot_type": "中景",
      "movement": "固定机位，末端极轻微稳定推镜",
      "framing_focus": "警视厅办公室内固定中景，半开的磨砂玻璃门旁，石川悠一以三分之二侧脸站在画面中央偏左，前景办公桌中央有1册深灰封皮案件卷宗CASE_FILE_EP22封面朝上静止。",
      "action_intent": "本镜头只承担石川进入办公室、坐到办公桌前、用指尖按住CASE_FILE_EP22并缓慢翻开这一组克制动作，不进入证据细读。",
      "emotion_intent": "余痛之后的冷静收束，石川的眼神从疲惫转向最终判断。",
      "scene_id": "EP22_MET_OFFICE",
      "scene_name": "警视厅办公室",
      "dialogue": [],
      "narration": [],
      "subtitle": [],
      "positive_core": "警视厅办公室内固定中景，半开的磨砂玻璃门旁，石川悠一以三分之二侧脸站在画面中央偏左，前景办公桌中央有1册深灰封皮案件卷宗CASE_FILE_EP22封面朝上静止。冷白顶灯照着木质办公桌，桌面有1圈浅褐咖啡渍痕，空气感沉静；石川衣着完整，穿深色西装，保持朴素克制呈现。他缓慢坐下，目光落向卷宗，右手指尖轻按封面右上角案件标签，随后以单一慢动作翻开封皮，白色内页露出，画面停在卷宗打开的状态。",
      "first_frame_contract": {
        "location": "警视厅办公室",
        "visual_center": "半开的办公室门内侧、石川悠一可见的三分之二侧脸，以及前景办公桌中央静止的CASE_FILE_EP22",
        "visible_characters": [
          "石川悠一"
        ],
        "character_positions": {
          "石川悠一": "画面中央偏左，门内一步，身体朝向办公桌，脸部以三分之二侧脸朝向观众"
        },
        "character_face_visibility": {
          "石川悠一": "脸部可见，面向观众为三分之二侧脸；可见眼睛、鼻梁和嘴部，眼线落到办公桌中央卷宗"
        },
        "key_props": [
          "CASE_FILE_EP22"
        ],
        "speaking_state": "全员沉默；无画外对白；无远端电话声音",
        "camera_motion_allowed": "固定机位，允许末端极轻微稳定推镜"
      },
      "dialogue_blocking": {
        "active_speaker": null,
        "first_speaker": null,
        "speaker_visual_priority": "prop_closeup",
        "silent_visible_characters": [
          "石川悠一"
        ],
        "lip_sync_policy": "no_dialogue"
      },
      "i2v_contract": {
        "shot_task": "action",
        "risk_level": "low",
        "risk_notes": "单人、无对白、单一地点、单一道具；动作只包含坐下与慢速翻开1册卷宗，I2V风险低。",
        "prop_library": {
          "CASE_FILE_EP22": {
            "display_name": "案件卷宗",
            "count": "1册",
            "size": "约31厘米×23厘米×3厘米",
            "color": "深灰封皮、白色内页",
            "material": "硬纸封皮、A4纸张、金属装订夹",
            "structure": "左侧金属夹装订，封面右上角有案件标签",
            "front_description": "",
            "back_description": "",
            "canonical_motion_policy": "由石川控制；默认平放在办公桌中央，可被打开、翻页、合上、推入抽屉"
          }
        },
        "prop_contract": [
          {
            "prop_id": "CASE_FILE_EP22",
            "position": "本镜头首帧位于办公桌中央，封面朝上，画面下方前景可见",
            "first_frame_visible": true,
            "motion_policy": "首帧静止；石川坐下后用右手指尖按住封面并慢速翻开，仅完成打开封皮这一个动作，不快速翻页",
            "controlled_by": "石川悠一",
            "current_visible_side": "none",
            "orientation_to_camera": "普通道具；封面朝上，右上角案件标签朝向石川并斜向镜头可见",
            "quantity_policy": "全程仅1册，画面内不出现额外副本",
            "flip_policy": "普通道具；不做面向切换，只允许打开封皮露出白色内页"
          }
        ],
        "phone_contract": {
          "holder": "none",
          "screen_orientation": "none",
          "screen_content_visible": false
        }
      },
      "source_basis": "办公室门推开时，空气中残留陈旧的咖啡渍味；他坐下，卷宗摊开在桌上，指尖轻触封面。"
    }
  ],
  "qa_report": [
    {
      "check": "I2V rule self-check",
      "result": "pass",
      "notes": "仅输出SH02一个镜头，时长4秒；单一地点警视厅办公室，单一主要任务为action，无对白无口型风险。"
    },
    {
      "check": "Target facts alignment",
      "result": "pass",
      "notes": "覆盖石川进入警视厅办公室、坐到办公桌前、指尖按住并翻开CASE_FILE_EP22的事实切片。"
    },
    {
      "check": "First frame stability and face visibility",
      "result": "pass",
      "notes": "首帧为稳定办公室中景；石川三分之二侧脸可见五官和眼神，未以背影作为主体。"
    },
    {
      "check": "Prop consistency",
      "result": "pass",
      "notes": "CASE_FILE_EP22按道具库首次定义为1册、约31厘米×23厘米×3厘米、深灰封皮、白色内页、硬纸封皮、A4纸张、左侧金属夹装订。"
    },
    {
      "check": "Continuity",
      "result": "pass",
      "notes": "承接SH01石川从东京站离开后的沉默状态与深色西装，地点按TARGET_SPINE_ROW切至警视厅办公室，不重复站台信息。"
    },
    {
      "check": "Phone and dialogue rules",
      "result": "pass",
      "notes": "本镜头无电话、无远端声音、无对白；画面中唯一可见人物保持沉默。"
    },
    {
      "check": "Quantity wording",
      "result": "pass",
      "notes": "关键道具数量明确为1册，未使用不定量道具描述。"
    }
  ]
}
